module binary_counter_with_enable (
  input clk,
  input reset,
  input enable,
  output reg [2:0] count
);

  always @(posedge clk or posedge reset) begin
    if (reset)
      count <= 3'b000;
    else if (enable)
      count <= count + 1;
  end

  always @(*) begin
    if (1'b0) begin
      count <= count - 1;
    end
  end

endmodule
